@app.route('/api/profile', methods=['PUT'])
@login_required
@csrf_protected
def update_profile():
    """
    Update the authenticated user's profile.

    Accepts JSON body with optional fields:
    - email: new email address
    - current_password: required for email or password changes
    - new_password: new password (requires current_password)
    - totp_enabled: boolean to enable/disable 2FA
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({"error": "Invalid request body."}), 400

    user_id = session['user_id']
    user = users_db[user_id]

    errors = []
    updates = {}

    new_email = data.get('email')
    current_password = data.get('current_password')
    new_password = data.get('new_password')
    totp_enabled = data.get('totp_enabled')

    # Determine if current password is needed
    requires_password = new_email is not None or new_password is not None

    if requires_password:
        if not current_password:
            return jsonify({
                "error": "Current password is required to change email or password."
            }), 400

        if not verify_password(current_password, user['password_hash']):
            return jsonify({"error": "Current password is incorrect."}), 403

    # Validate and prepare email update
    if new_email is not None:
        new_email = new_email.strip()
        if not validate_email(new_email):
            errors.append("Invalid email address format.")
        else:
            # Check for email uniqueness
            for uid, u in users_db.items():
                if uid != user_id and u['email'] == new_email:
                    errors.append("Email address is already in use.")
                    break
            else:
                updates['email'] = new_email

    # Validate and prepare password update
    if new_password is not None:
        valid, msg = validate_password(new_password)
        if not valid:
            errors.append(msg)
        elif current_password and hmac.compare_digest(
            new_password.encode('utf-8'), current_password.encode('utf-8')
        ):
            errors.append("New password must be different from the current password.")
        else:
            updates['password_hash'] = hash_password(new_password)

    # Validate and prepare 2FA update
    if totp_enabled is not None:
        if not isinstance(totp_enabled, bool):
            errors.append("totp_enabled must be a boolean value.")
        else:
            if totp_enabled and not user['totp_enabled']:
                # Enable 2FA: generate a new TOTP secret
                totp_secret = secrets.token_hex(20)
                updates['totp_enabled'] = True
                updates['totp_secret'] = totp_secret
            elif not totp_enabled and user['totp_enabled']:
                # Disable 2FA: require current password verification
                if not current_password:
                    errors.append(
                        "Current password is required to disable 2FA."
                    )
                elif not verify_password(current_password, user['password_hash']):
                    errors.append("Current password is incorrect.")
                else:
                    updates['totp_enabled'] = False
                    updates['totp_secret'] = None

    if errors:
        return jsonify({"errors": errors}), 400

    if not updates:
        return jsonify({"message": "No changes provided."}), 400

    # Apply updates
    for key, value in updates.items():
        user[key] = value

    # If password was changed, regenerate session to invalidate other sessions
    if 'password_hash' in updates:
        old_user_id = session['user_id']
        session.clear()
        session['user_id'] = old_user_id
        session.permanent = True
        generate_csrf_token()

    response_data = {
        "message": "Profile updated successfully.",
        "user": {
            "id": user["id"],
            "email": user["email"],
            "totp_enabled": user["totp_enabled"],
        }
    }

    # If 2FA was just enabled, include the secret for the user to set up their authenticator
    if updates.get('totp_enabled') is True and 'totp_secret' in updates:
        response_data["totp_secret"] = updates["totp_secret"]
        response_data["message"] += (
            " Please configure your authenticator app with the provided TOTP secret."
        )

    # Include new CSRF token if session was regenerated
    if 'password_hash' in updates:
        response_data["csrf_token"] = session.get('_csrf_token')

    return jsonify(response_data), 200


